 48   if (C->isSubsetOf(Demanded))
 49     return false;
 50 
 51   // This instruction is producing bits that are not demanded. Shrink the RHS.
 52   I->setOperand(OpNo, ConstantInt::get(Op->getType(), *C & Demanded));
 53 
 54   return true;
 55 }
